import { Lesson } from './types';
import { createLesson } from './data_helpers';

export const redLessonsB1: Lesson[] = [
  createLesson('g2-red-b1-l1', 'L1: 2ª Série — Aprofundando a Redação', 'redacao', 'A 2ª série é o ano de consolidar e aprofundar. Revisão rápida das 5 competências e estrutura da dissertação. Diagnóstico: escreva uma redação sobre o tema proposto em 60 minutos. Identificação das maiores dificuldades. Metas do ano: aumentar a nota em pelo menos 100-150 pontos em relação ao final da 1ª série. A mentalidade: redação é habilidade, não talento — você pode e vai melhorar. O que mudar: mais leitura, mais prática de argumentação, repertório cultural mais robusto.', ['Escreva a redação de diagnóstico do 2ª série (60 minutos).', 'Analise sua redação: compare com as melhores que você produziu na 1ª série. O que está diferente?']),
  createLesson('g2-red-b1-l2', 'L2: Argumentação Avançada — Lógica Formal', 'redacao', 'Introdução à lógica argumentativa. Argumento válido vs. argumento verdadeiro. Tipos de raciocínio: dedutivo ("todos os X são Y; Z é X; logo Z é Y"), indutivo (do particular ao geral), abdutivo (inferência da melhor explicação). Falácias lógicas que enfraquecem argumentos: generalização precipitada, apelo à autoridade incorreto, post hoc ergo propter hoc (confundir correlação com causalidade), falsa dicotomia, argumento ad hominem. Identificar e evitar falácias na redação. Construir argumentos logicamente sólidos.', ['Identifique as falácias lógicas nestes argumentos de redações reais.', 'Reescreva este argumento falacioso tornando-o logicamente sólido.']),
  createLesson('g2-red-b1-l3', 'L3: A Tese — Precisão e Originalidade', 'redacao', 'Elevando a tese. Tese de nível 1 (fraco): "A violência é um problema sério no Brasil." Tese de nível 3 (médio): "A violência urbana está relacionada com a desigualdade social." Tese de nível 5 (forte): "A perpetuação da violência urbana no Brasil reflete a falência de políticas integradas de segurança, educação e combate à desigualdade, que atingem desproporcionalmente as populações negras e periféricas." O que torna uma tese de nível 5: recorte preciso, relação causal ou sistêmica, dimensão social específica. Prática: reformular teses de nível 1 em nível 5.', ['Reformule estas 5 teses fracas em teses fortes (nível 5).', 'Escreva uma tese forte para cada um destes temas: saúde mental, meio ambiente, tecnologia.']),
  createLesson('g2-red-b1-l4', 'L4: Repertório Filosófico na Redação', 'redacao', 'Usando filosofia de forma pertinente na redação. Filósofos e conceitos mais úteis. Aristóteles: o homem é um animal político; amizade cívica como base da democracia. Kant: imperativo categórico ("aja como se sua ação pudesse ser lei universal"); dignidade humana. Rousseau: contrato social, vontade geral. Marx: alienação, luta de classes, estrutura e superestrutura. Foucault: relações de poder, biopoder, vigilância. Bourdieu: habitus, capital cultural, campo social. Simone de Beauvoir: "não se nasce mulher, torna-se." Hannah Arendt: banalidade do mal, espaço público. Como citar sem ser artificial.', ['Aplique o conceito de Bourdieu de "capital cultural" em um parágrafo sobre desigualdade educacional.', 'Para cada filósofo listado, escreva 1 frase que mostra como você usaria o conceito em uma redação.']),
  createLesson('g2-red-b1-l5', 'L5: Repertório Sociológico e Histórico', 'redacao', 'Sociologia e História como fontes de repertório. Durkheim: anomia social (desordem normativa), solidariedade mecânica/orgânica. Weber: ética protestante e o capitalismo, dominação racional-legal. Zygmunt Bauman: modernidade líquida (relações fluidas, identidades instáveis). Stuart Hall: identidade cultural pós-colonial. Eventos históricos como repertório: Abolição (1888), Revolução de 1930, Ditadura Militar (1964-1985), Constituição 1988 (redemocratização), Rio+92, Declaração Universal dos Direitos Humanos (1948). Precisão histórica: datas e fatos corretos.', ['Use o conceito de "modernidade líquida" de Bauman em um parágrafo sobre relacionamentos na era digital.', 'Para qual tema cada evento histórico listado seria mais pertinente? Justifique.']),
  createLesson('g2-red-b1-l6', 'L6: Introdução — Estratégias de Alto Nível', 'redacao', 'Introduções que se destacam da média. Estratégia da "câmera que abre": começar com o específico (um caso, uma cena) e ir abrindo para o geral (o problema social). Estratégia do paradoxo: "O Brasil é o 6º produtor de alimentos do mundo, mas 19 milhões de brasileiros passam fome." Estratégia da contextualização filosófica: "Aristóteles, ao definir o homem como animal político, pressupunha que a convivência em sociedade exige normas e instituições..." Estratégia da citação indireta: "A filósofa Hannah Arendt apontava que..." Evitar os clichês mais comuns.', ['Escreva 4 introduções diferentes para o mesmo tema usando 4 estratégias diferentes.', 'Identifique os clichês de introdução neste conjunto de redações e sugira alternativas.']),
  createLesson('g2-red-b1-l7', 'L7: Desenvolvimento — Parágrafos de Nível Avançado', 'redacao', 'Parágrafos de desenvolvimento de altíssimo nível. Estrutura: Micro-tese do parágrafo → Desenvolvimento em 2-3 camadas → Evidência múltipla → Conexão explícita com a tese. Camadas do desenvolvimento: 1ª camada (o que é), 2ª camada (por que acontece / causas), 3ª camada (quem é afetado / consequências). Evidência múltipla: combinar dado + lei + conceito teórico no mesmo parágrafo. Exemplo: "Dados do IBGE revelam que X (dado). Tal fenômeno decorre de Y (causa, com conceito teórico). Z (consequência, com referência normativa)." 8-10 linhas.', ['Escreva um parágrafo de desenvolvimento com 3 camadas sobre o tema proposto.', 'Analise este parágrafo fraco: quantas camadas tem? Reescreva com 3 camadas.']),
  createLesson('g2-red-b1-l8', 'L8: Conclusão — Síntese e Proposta Criativa', 'redacao', 'Conclusão de nível alto. A conclusão não é resumo — é síntese: uma nova perspectiva que emerge dos argumentos. Elementos da conclusão avançada: retomada sintética da tese (nova formulação, não cópia), transição para a proposta (conectivo de conclusão), proposta com 5 elementos (específica, criativa, viável), frase final de impacto (citação, futuro projetado, apelo aos valores, circularidade com a introdução). A proposta como o ponto mais específico de toda a redação. Prática: escrever 3 conclusões para o mesmo tema com propostas diferentes.', ['Escreva 3 conclusões com propostas de intervenção diferentes para o mesmo tema.', 'Qual das 3 propostas é mais específica? Por quê?']),
  createLesson('g2-red-b1-l9', 'L9: Primeira Redação Completa — 2ª Série', 'redacao', 'Primeira redação completa do ano na 2ª série: tema social com textos motivadores, 60 minutos. Demonstrar crescimento: tese mais precisa, argumentos com múltiplas camadas, repertório filosófico ou sociológico, proposta de intervenção específica. Processo rigoroso: 10 min planejar (por escrito no rascunho), 40 min escrever, 10 min revisar com checklist. Avaliação e devolutiva: análise por competência + comparação com a redação de diagnóstico (progresso).', ['Escreva a primeira redação completa da 2ª série (60 minutos).', 'Compare esta redação com a de diagnóstico: houve evolução qualitativa? Em que aspecto?']),
  createLesson('g2-red-b1-l10', 'L10: Temas de Direitos Humanos', 'redacao', 'Direitos Humanos como tema e como princípio. Declaração Universal dos DH (1948): 30 artigos. Gerações dos DH: 1ª geração (civis e políticos), 2ª (econômicos, sociais, culturais), 3ª (difusos — meio ambiente, paz). Constituição Federal 1988: base dos DH no Brasil. Violações de DH no Brasil: tortura, trabalho escravo, feminicídio, violência policial. A Competência 5 exige: proposta que respeite os DH. Como os DH orientam a argumentação. Prática: redação sobre garantia de direitos a grupos vulneráveis.', ['Planeja uma redação sobre: "Desafios para garantir os direitos humanos de populações em situação de rua".', 'Como você garantiria que sua proposta de intervenção respeita os direitos humanos?']),
  createLesson('g2-red-b1-l11', 'L11: Temas de Gênero e Diversidade', 'redacao', 'Temas de gênero e diversidade no ENEM. Feminismo e violência contra a mulher: feminicídio, assédio, desigualdade salarial. Comunidade LGBTQIA+: discriminação, direitos. Pessoas com deficiência: inclusão, acessibilidade. Povos indígenas: demarcação de terras, direitos culturais. Idosos: violência, abandono, direitos. Como abordar com equilíbrio e respeito aos DH. Léxico adequado: usar a terminologia correta mostra respeito e conhecimento. Prática: redação sobre combate à discriminação de gênero no mercado de trabalho.', ['Escreva um parágrafo sobre desigualdade salarial de gênero usando dados reais e argumento sólido.', 'Como você abordaria o tema "LGBTQIA+" em uma redação do ENEM com respeito e sem fuga?']),
  createLesson('g2-red-b1-l12', 'L12: Coesão de Alto Nível', 'redacao', 'Coesão sofisticada: além dos conectivos básicos. Coesão lexical: retomada por sinônimo, hiperônimo, antônimo, metonímia — criando uma "teia semântica" no texto. Coesão referencial avançada: demonstrativos para retomar orações completas ("Essa realidade...", "Tal fenômeno...", "Diante disso..."). Elipse temática: omitir o sujeito quando é claro (criar fluência). Progressão temática: o "gancho" entre parágrafos — a última frase de um parágrafo cria expectativa para o próximo. Reescrever um texto com coesão ruim para demonstrar os recursos.', ['Analise a coesão desta redação: identifique cada mecanismo usado e avalie sua eficácia.', 'Reescreva este texto com coesão fraca tornando-o coeso com recursos variados.']),
  createLesson('g2-red-b1-l13', 'L13: Análise de Redações Nota 1000', 'redacao', 'Análise aprofundada de redações nota 1000 do ENEM. Estudo de caso: 3 redações de diferentes anos, diferentes temas. Para cada uma: analisar competência por competência, identificar os recursos usados, encontrar o que é excepcional (não apenas "bom"). Identificar padrões das redações nota 1000: tese precisa, argumentação em camadas, repertório pertinente, proposta detalhada, coesão variada, conclusão com impacto. O que você pode imitar na sua escrita (não o conteúdo — a estrutura e os recursos). Internalizar critérios de excelência.', ['Analise esta redação nota 1000 e identifique: o que a coloca neste nível em cada competência?', 'Escreva um parágrafo de desenvolvimento tentando imitar o nível de argumentação desta redação nota 1000.']),
  createLesson('g2-red-b1-l14', 'L14: Produção sob Pressão', 'redacao', 'Simulando a pressão do ENEM. Redação em 50 minutos (não 60 — para treinar com margem de segurança). Foco: não perder tempo planejando demais — o planejamento deve ser rápido e eficiente (máximo 8 minutos). Técnicas de gerenciamento do tempo de prova: olhar o relógio a cada 15 minutos, saber quando parar o desenvolvimento e começar a conclusão (mesmo que incompleto, uma conclusão é melhor que nenhuma). Lidando com o "branco": estratégias para destravar quando não consegue escrever. O ENEM é uma maratona — prepare-se para isso.', ['Escreva uma redação em 50 minutos (não 60). Como o tempo menor afetou sua escrita?', 'Qual é sua estratégia quando você "trava" no meio da redação?']),
  createLesson('g2-red-b1-l15', 'L15: Temas de Ciência e Tecnologia', 'redacao', 'Ciência e tecnologia como temas de redação. Subtemas: IA e mercado de trabalho, privacidade digital (LGPD), desinformação/fake news, acesso à tecnologia, biotecnologia e ética, energias renováveis, exploração espacial. Repertório específico: LGPD (13.709/2018), Marco Civil da Internet (12.965/2014), Klaus Schwab ("A Quarta Revolução Industrial"), Carl Sagan sobre ciência e pseudociência. Desafios éticos da tecnologia: quem decide? A tecnologia é neutra? Prática: redação sobre os impactos da IA no mercado de trabalho brasileiro.', ['Escreva uma redação sobre "Desafios éticos da Inteligência Artificial no Brasil" com repertório e proposta.', 'Como você abordaria o tema fake news com uma proposta de intervenção que respeite a liberdade de expressão?']),
  createLesson('g2-red-b1-l16', 'L16: Escrita como Expressão de Cidadania', 'redacao', 'A dissertação argumentativa como ato cidadão. Ao escrever uma redação do ENEM, você não está apenas "respondendo a uma prova" — você está exercendo sua capacidade de argumentar sobre problemas reais do Brasil. A escrita como poder: quem sabe escrever bem tem mais acesso a direitos, empregos, influência. A redação como diálogo com a sociedade: o que você diria a um formulador de políticas públicas? Conectar sua redação com a realidade que você conhece: Tocantins, sua escola, sua família, sua comunidade.', ['Qual é o problema social que mais te afeta em Palmas ou no Tocantins? Escreva uma redação sobre ele.', 'Como a habilidade de argumentar por escrito te dá poder na sociedade?']),
  createLesson('g2-red-b1-l17', 'L17: Revisão por Competência — Avaliação Cruzada', 'redacao', 'Revisão sistemática de todas as competências com exemplos reais. C1: lista de 20 erros de norma culta mais comuns em redações de 2ª série. C2: 10 formas de tangenciar o tema (e como evitar). C3: 5 tipos de argumento e como desenvolvê-los em 3 camadas. C4: 15 conectivos sofisticados e seus usos corretos. C5: modelo completo de proposta com os 5 elementos bem especificados. Avaliação cruzada: cada aluno avalia a redação de outro usando a grade do ENEM.', ['Faça a avaliação cruzada: avalie a redação de um colega competência por competência.', 'Receba o feedback e identifique: qual é sua competência mais fraca consistentemente?']),
  createLesson('g2-red-b1-l18', 'L18: Revisão do Bimestre 1 — 2ª Série', 'redacao', 'Revisão do 1º Bimestre: diagnóstico, lógica argumentativa, tese avançada, repertório (filosófico e sociológico), introdução de alto nível, parágrafos em camadas, conclusão com proposta criativa, primeira redação da 2ª série, direitos humanos, gênero/diversidade, coesão avançada, análise de nota 1000, pressão de tempo, ciência/tecnologia, escrita como cidadania. Segunda redação do semestre como avaliação. Análise de evolução.', ['Escreva a redação de avaliação do 1º Bimestre (60 minutos).', 'Compare as 2 redações do semestre: como a qualidade evoluiu?']),
];

export const redLessonsB2: Lesson[] = [
  createLesson('g2-red-b2-l1', 'L1: Repertório Cultural — Literatura na Redação', 'redacao', 'Usando literatura como repertório de forma pertinente e sofisticada. Como citar obras literárias: indiretamente ("O escritor Machado de Assis, em Dom Casmurro, retratava...") ou diretamente (trecho curto entre aspas). Conexão pertinente: a obra deve ilustrar ou apoiar o argumento — não ser uma decoração. Obras literárias por tema: violência ("Capitães da Areia"), desigualdade ("Vidas Secas"), escravidão ("O Navio Negreiro"), identidade ("Grande Sertão: Veredas"), questão feminina ("A Hora da Estrela"), sustentabilidade ("Ideias para Adiar o Fim do Mundo").', ['Para cada tema proposto, indique uma obra literária pertinente e explique a conexão.', 'Escreva um parágrafo argumentativo usando "Vidas Secas" como repertório para o tema de desigualdade.']),
  createLesson('g2-red-b2-l2', 'L2: Argumento Causal Avançado', 'redacao', 'O argumento causal é poderoso quando mostra uma cadeia de causas e efeitos — não apenas uma relação simples. Cadeia causal: A → B → C → D (cada etapa explicada). Exemplo: "A falta de regulamentação das redes sociais (A) permite a proliferação de desinformação (B), que afeta as decisões eleitorais (C), comprometendo a democracia (D)." Diferença entre correlação e causalidade (não confundir!). Argumento de reversibilidade: se X causa Y, então eliminar X previne Y. Prática: construir cadeias causais para 3 temas diferentes.', ['Construa uma cadeia causal de 4 etapas para o tema: "Impacto do analfabetismo na participação cidadã".', 'Identifique se estas relações são causais ou apenas correlações. Justifique.']),
  createLesson('g2-red-b2-l3', 'L3: Proposta de Intervenção — Nível Máximo', 'redacao', 'Proposta de intervenção de nível 200 (nota máxima). Características: agente institucional específico, ação com verbo preciso, meio detalhado e viável, finalidade clara, efeito esperado quantificável ou verificável. Exemplo (tema: violência contra a mulher): "Cabe ao Ministério da Educação, em parceria com as Secretarias Estaduais de Educação — como as do Tocantins —, instituir programas de educação para igualdade de gênero no ensino fundamental e médio, mediante criação de componente curricular obrigatório sobre equidade e combate à violência doméstica, a fim de formar gerações mais conscientes, reduzindo os índices de feminicídio a longo prazo." Análise: todos os 5 elementos presentes.', ['Escreva 3 propostas de nível 200 para 3 temas diferentes: cada uma com todos os 5 elementos.', 'Avalie estas propostas em relação ao nível 200: o que falta em cada uma?']),
  createLesson('g2-red-b2-l4', 'L4: Temas de Política e Democracia', 'redacao', 'Temas políticos no ENEM: democracia, participação cidadã, polarização política, transparência pública, corrupção, direito ao voto, representatividade. Repertório: Constituição Federal 1988 (Art. 1° — democracia como fundamento), Alexis de Tocqueville ("A Democracia na América"), Hannah Arendt (espaço público e ação política), dados do TSE (abstenção eleitoral), índices de corrupção (Transparência Internacional). Como abordar política sem tomar partido (não defenda partidos — defenda princípios democráticos). Prática: redação sobre crise na representação política.', ['Como você abordaria o tema da corrupção em uma redação sem defeder ou atacar partidos específicos?', 'Escreva um parágrafo sobre participação política usando dados reais e conceito teórico.']),
  createLesson('g2-red-b2-l5', 'L5: Temas Ambientais Avançados', 'redacao', 'Aprofundando temas ambientais. Mudanças climáticas: Acordo de Paris (2015), NDCs (Contribuições Determinadas Nacionalmente), carbono zero, IPCC. Desmatamento: Código Florestal (12.651/2012), PRODES (INPE — dados de desmatamento), Fundo Amazônia. Recursos hídricos: crise hídrica, saneamento básico (Lei 14.026/2020), Agenda 2030 ODA 6. Segurança alimentar: FAO, fome zero (ODS 2), agrotóxicos, agroecologia. Biodiversidade: COP15 (Biodiversidade), IPBES. Reservatório de argumentos ambientais com dados atuais.', ['Para o tema "desmatamento da Amazônia", construa 2 argumentos distintos com dados reais.', 'Escreva uma redação sobre segurança alimentar com repertório da FAO e argumento sobre produção sustentável.']),
  createLesson('g2-red-b2-l6', 'L6: Terceira Redação — Simulado Rigoroso', 'redacao', 'Terceiro simulado de redação da 2ª série. Tema com textos motivadores complexos (nível mais alto que 1ª série). 60 minutos rigorosos. Expectativa: tese de nível avançado, argumentos em camadas, repertório filosófico/sociológico/literário pertinente, coesão sofisticada, proposta com todos os 5 elementos. Avaliação criteriosa: o professor aplica a grade como a banca do ENEM. Comparação de evolução: trajetória das 3 redações escritas na 2ª série até aqui.', ['Escreva o simulado 3 de redação (60 minutos rigorosos).', 'Após a devolutiva: qual foi seu ponto de maior evolução? O que ainda precisa melhorar?']),
  createLesson('g2-red-b2-l7', 'L7: Temas Econômicos e Sociais', 'redacao', 'Economia e sociedade como temas de redação. Subtemas: desigualdade de renda (Coeficiente de Gini), pobreza extrema, reforma tributária, renda básica universal, desemprego, informalidade, trabalho decente (OIT), crise de habitação, mobilidade social. Repertório: Thomas Piketty ("O Capital no Século XXI" — desigualdade), Amartya Sen (desenvolvimento como liberdade), dados IBGE/PNAD, IPEA. Como abordar economia sem ser economista: foco no impacto social, não nos mecanismos técnicos. Prática: redação sobre desigualdade social.', ['Escreva uma redação sobre: "Estratégias para reduzir a desigualdade de renda no Brasil".', 'Use Thomas Piketty de forma pertinente em um parágrafo sobre desigualdade de riqueza.']),
  createLesson('g2-red-b2-l8', 'L8: Textos Motivadores — Como Usá-los', 'redacao', 'Os textos motivadores são frequentemente mal usados nas redações. Como usar corretamente: referenciar de forma indireta ("Conforme exposto no texto 2..."), incorporar dados do texto sem copiar, usar o texto como ponto de partida para ir além. Como não usar: copiar frases inteiras (nota 0), resumir os textos em vez de argumentar, ignorar completamente os textos. Os textos motivadores introduzem o tema — eles não são o argumento. Seu conhecimento externo é o que diferencia sua redação. Exercício: usar os textos motivadores de forma sofisticada.', ['Leia estes textos motivadores e planeje como os usar na redação (sem copiar).', 'Escreva uma introdução que dialogue com os textos motivadores sem copiá-los.']),
  createLesson('g2-red-b2-l9', 'L9: Coesão — Exercícios Avançados', 'redacao', 'Exercícios intensivos de coesão de alto nível. Exercício 1: reescrever um parágrafo usando apenas sinônimos para retomar o tema (sem repetir a palavra-chave nenhuma vez). Exercício 2: conectar dois parágrafos sem usar um conectivo explícito (usando a última frase de um como gancho para o primeiro do outro). Exercício 3: criar uma teia semântica: mapeando todas as palavras relacionadas ao tema que podem ser usadas para substituição. Exercício 4: identificar problemas de coesão em redações nota 600 e corrigi-los. Alta coesão = texto que flui naturalmente.', ['Execute os 4 exercícios de coesão avançada propostos.', 'Reescreva um parágrafo de uma redação anterior tornando-o mais coeso sem perder o conteúdo.']),
  createLesson('g2-red-b2-l10', 'L10: Temas de Saúde Pública', 'redacao', 'Saúde pública como tema recorrente no ENEM. Subtemas: acesso ao SUS, saúde da mulher (mortalidade materna), saúde indígena, saúde mental, obesidade, vacinação (antivacina), saneamento básico. Repertório: Lei Orgânica do SUS (8.080/1990), Constituição Art. 196, dados do DATASUS, relatórios da OMS. Conceito de "determinantes sociais da saúde": renda, educação, moradia, saneamento afetam a saúde. A saúde como direito, não mercadoria. Prática: redação sobre os desafios do acesso à saúde mental no Brasil.', ['Escreva uma redação completa sobre: "Desafios para garantir o acesso à saúde mental como direito universal no Brasil".', 'Como você conecta saúde mental com determinantes sociais? Desenvolva o argumento.']),
  createLesson('g2-red-b2-l11', 'L11: Revisão de Norma Culta — Nível 2ª Série', 'redacao', 'Revisão de norma culta com foco nos erros mais frequentes em redações de 2ª série. Concordância: "a maioria dos jovens SOFRE" ou "SOFREM"? (singular — coletivo + partitivo). "Um dos problemas que AFETA" ou "AFETAM" o Brasil? (plural — concordância com o relativo). Regência: "implicar EM" ou "implicar A"? (implica = envolve, VTD; implicar em = resultar em, VTI). Crase: "à medida que" (sempre crase); "a medida que" = errado. Colocação: "Propõe-se", não "Se propõe" (norma culta escrita). 20 questões de revisão de norma.', ['Resolva as 20 questões de norma culta específicas para 2ª série.', 'Quais são os 3 erros de norma culta que você mais comete? Crie um cartão de revisão.']),
  createLesson('g2-red-b2-l12', 'L12: Quarta Redação — Verificação de Progresso', 'redacao', 'Quarta redação: ponto de verificação do semestre. Tema proposto pelo professor. 60 minutos. Aplicando todos os aprendizados: tese avançada, argumentação em camadas, repertório pertinente, coesão sofisticada, proposta de nível 200. Análise de evolução: comparar as 4 redações escritas na 2ª série. Projeção de nota: em que patamar você está agora? Para a 3ª série, você precisa de uma base sólida — esta é a redação que mostra o que você consolidou.', ['Escreva a 4ª redação da 2ª série (60 minutos).', 'Compare as 4 redações: qual competência teve maior evolução? Qual ainda está fraca?']),
  createLesson('g2-red-b2-l13', 'L13: Temas Culturais e Identidade', 'redacao', 'Cultura e identidade como temas de redação. Subtemas: patrimônio cultural, diversidade cultural, culturas indígenas, cultura afro-brasileira, influência estrangeira na cultura brasileira, indústria cultural, cultura popular vs. cultura erudita, internet e globalização cultural. Repertório: Constituição Art. 215-216 (cultura como direito), UNESCO (patrimônio imaterial), Theodor Adorno ("Indústria Cultural"), Hall (identidade cultural pós-colonial). Brasil como nação multicultural: riqueza e tensões. Práticas culturais do Tocantins como repertório legítimo.', ['Escreva um parágrafo sobre a valorização das culturas indígenas no Brasil com argumento sólido e proposta.', 'Como você usaria a cultura tocantinense (Cerrado, povos indígenas, festas populares) em uma redação sobre identidade?']),
  createLesson('g2-red-b2-l14', 'L14: Leitura de Jornais como Prática', 'redacao', 'Ler jornais e revistas regularmente como parte da preparação. Como ler produtivamente: 20-30 minutos por dia, focando em editoriais, artigos de opinião, análises. Fontes recomendadas: Nexo Jornal (contextualizador), Agência Pública (jornalismo investigativo), Piauí (análise aprofundada), Le Monde Diplomatique Brasil (perspectiva crítica). Como transformar a leitura em repertório: anotar dados, citações, eventos, conceitos. Criando um "diário de repertório": cada leitura relevante vira uma ficha. Este hábito vale mais do que qualquer lista pronta de temas.', ['Leia 3 artigos de opinião em um jornal/revista de qualidade. Extraia 1 dado e 1 argumento de cada.', 'Monte 3 fichas de repertório a partir das leituras de hoje.']),
  createLesson('g2-red-b2-l15', 'L15: Temas Educacionais', 'redacao', 'Educação como tema de redação — profundidade. Subtemas: qualidade da educação básica, acesso ao ensino superior, cotas, educação indígena e quilombola, educação especial/inclusiva, financiamento da educação (Fundeb), analfabetismo funcional, evasão escolar, valorização dos professores. Repertório: INEP (IDEB, PISA), LDB (9.394/1996), Constituição Art. 205-214, Paulo Freire, dados PNAD. A educação como direito e como alavanca de desenvolvimento. Proposta: o que especificamente pode ser feito para melhorar a educação no Brasil?', ['Escreva uma redação completa sobre: "O papel da educação inclusiva na redução das desigualdades".', 'Que 3 ações específicas o governo do Tocantins poderia fazer para melhorar a educação?']),
  createLesson('g2-red-b2-l16', 'L16: Redação de Práticas Avançadas — Workshop', 'redacao', 'Workshop de redação: sessão prática intensa. Parte 1: 15 minutos — escrever apenas o planejamento completo de uma redação (tese + 2 argumentos + evidências + proposta). Parte 2: 30 minutos — escrever apenas os 2 parágrafos de desenvolvimento com foco total na argumentação. Parte 3: 15 minutos — revisão de norma culta e coesão usando o checklist. Feedback imediato do professor durante a escrita. Foco intenso em uma parte da redação de cada vez — desenvolvimento da consciência metacognitiva.', ['Execute o workshop de redação em 3 partes (15+30+15 minutos).', 'Qual das 3 partes foi mais difícil? Por que essa parte em específico desafia você?']),
  createLesson('g2-red-b2-l17', 'L17: Revisão do Semestre Completo', 'redacao', 'Revisão do 1º semestre completo de 2ª série. Conteúdos: argumentação lógica, tese avançada, repertório (filosófico, sociológico, literário), introdução de alto nível, parágrafos em camadas, conclusão criativa, textos motivadores, coesão avançada, temas (DH, gênero, ciência, política, ambiente, economia, saúde, cultura, educação), norma culta. Avaliação final do semestre: a 5ª redação. Reflexão: onde você estava no início do ano e onde está agora.', ['Escreva a 5ª redação (avaliação do semestre) em condições rigorosas.', 'Faça uma autoavaliação do seu desenvolvimento em Redação no 1º semestre da 2ª série.']),
  createLesson('g2-red-b2-l18', 'L18: Revisão do Bimestre 2', 'redacao', 'Revisão do 2º Bimestre: literatura como repertório, argumento causal avançado, proposta de nível 200, política/democracia, ambiente avançado, simulado 3, economia, textos motivadores, coesão avançada, saúde pública, norma culta nível 2ª série, quarta redação, temas culturais, leitura de jornais, educação. Balanço do 1º semestre. Planejamento para o 2º semestre: o que priorizar nos 2 últimos bimestres.', ['Participe do balanço do 1º semestre: o que você aprendeu sobre sua própria escrita?', 'Monte o plano de estudos de Redação para os 2 bimestres finais.']),
];

export const redLessonsB3: Lesson[] = [
  createLesson('g2-red-b3-l1', 'L1: 2º Semestre — Intensidade Máxima', 'redacao', 'Entrando no 2º semestre de 2ª série: foco máximo. Com o ENEM a 1 ano e meio de distância, cada redação conta. Metas do 2º semestre: atingir consistentemente 700+ em cada redação praticada. O que impede a maioria dos alunos de chegar lá: C3 fraca (argumento superficial), C5 vaga (proposta genérica). Plano de intensificação: uma redação completa por semana (2 na escola + 2 em casa). Cada redação deve ser revisada, receber feedback e ser corrigida. A escrita melhora com prática consistente — não com estudo teórico apenas.', ['Escreva sua primeira redação do 2º semestre. Compare com a primeira redação do ano: o crescimento é visível?', 'Qual é seu plano de prática semanal de redação para o 2º semestre?']),
  createLesson('g2-red-b3-l2', 'L2: Argumentação — Técnicas de Alto Impacto', 'redacao', 'Técnicas argumentativas de alto impacto para elevar a nota. Técnica 1: "Zoom out" — conectar o problema local a uma questão global. Ex.: "O analfabetismo funcional no Brasil (local) está inserido em uma crise global de educação (global), conforme apontam os dados do PISA..." Técnica 2: "Causa sistêmica" — mostrar que o problema não é individual, mas estrutural. Técnica 3: "Paradoxo produtivo" — usar uma contradição para aprofundar a análise. Técnica 4: "Consequência em cascata" — mostrar como o problema se amplifica. Prática com cada técnica.', ['Aplique cada uma das 4 técnicas em um parágrafo diferente sobre o mesmo tema.', 'Qual técnica argumentativa é mais natural para você? Qual é mais desafiadora?']),
  createLesson('g2-red-b3-l3', 'L3: Terceiro Bimestre — Tema Livre', 'redacao', 'Redação com tema escolhido pelo aluno. Demonstrando autonomia argumentativa: escolher um problema social que você conhece profundamente e argumentar sobre ele. A redação mais autêntica geralmente é a mais forte. Conectar sua experiência real (no Tocantins, na escola, na comunidade) com dados e teorias. O ENEM não sabe que você é de Palmas — mas você pode escrever sobre problemas que afetam o Tocantins com especificidade e autenticidade. Prática: escrever sobre um problema que você vivencia.', ['Escreva uma redação sobre um problema social real que você conhece na sua vida em Palmas/Tocantins.', 'O que tornou esta redação mais autêntica do que as redações sobre temas genéricos?']),
  createLesson('g2-red-b3-l4', 'L4: Revisão de Todos os Tipos de Argumento', 'redacao', 'Revisão completa e prática de todos os tipos de argumento. Argumento de autoridade: quando usar e como citar. Argumento de dados: precisão e pertinência. Argumento histórico: fatos do passado como evidência. Argumento por exemplificação: caso concreto e específico. Argumento causal: cadeia de causa e efeito. Argumento por analogia: comparação com situação similar. Argumento do consenso científico: ciência como evidência. Argumento da consequência: mostrar o que acontecerá se não agirmos. Um argumento por parágrafo, mas combinando tipos quando pertinente.', ['Para o tema proposto, escreva 8 argumentos usando um tipo diferente cada.', 'Qual tipo de argumento produz mais impacto no ENEM? Justifique com análise de questões.']),
  createLesson('g2-red-b3-l5', 'L5: Norma Culta — Revisão Exaustiva', 'redacao', 'Revisão final exaustiva de norma culta para a 2ª série. Lista dos 30 erros mais comuns em redações do ENEM. Categorias: ortografia (principais erros), acentuação (diferenças pós-reforma de 2009), concordância (todos os casos especiais), regência (verbos mais problemáticos), crase (todos os casos), colocação pronominal (regras e exceções), pontuação (vírgula que separa sujeito — NUNCA!, ponto-e-vírgula em enumeração). Criação do "manual pessoal de norma culta": os 10 erros que EU mais cometo.', ['Faça o teste de norma culta: 30 questões cobrindo todos os pontos revisados.', 'Crie seu manual pessoal: os 10 pontos de norma culta mais problemáticos para você.']),
  createLesson('g2-red-b3-l6', 'L6: Sexta Redação — Simulado Completo', 'redacao', 'Sexta redação: simulado em condições rigorosas de ENEM. Tema escolhido pelo professor com textos motivadores variados. 60 minutos exatos. Cálculo de nota estimada: cada competência de 0-200. Meta para esta redação: atingir ou superar 700 pontos (objetivo do 2º semestre). Análise detalhada: para chegar a 800+, o que precisa mudar? Feedback técnico e qualitativo. Comparação com todas as redações anteriores: trajetória completa do ano.', ['Escreva a 6ª redação em condições rigorosas.', 'Estime sua nota por competência. Qual é sua maior lacuna para atingir 800?']),
  createLesson('g2-red-b3-l7', 'L7: Temas Emergentes — Preparação Ampla', 'redacao', 'Preparando-se para temas que ainda não apareceram no ENEM mas podem aparecer. Temas emergentes: crise climática e migrações (refugiados climáticos), regulação de IA no Brasil, saúde mental pós-pandemia, direitos digitais, economia circular, bioma Cerrado, povo Yanomami, violência policial. Para cada tema emergente: identificar o problema social central, os aspectos contraditórios, repertório disponível, possível proposta de intervenção. Construindo flexibilidade para temas novos.', ['Para 2 temas emergentes, faça um planejamento completo de redação (tese, argumentos, proposta).', 'Como você abordaria um tema completamente novo sobre o qual não estudou nada específico?']),
  createLesson('g2-red-b3-l8', 'L8: Revisão de Estrutura — Começando Diferente', 'redacao', 'Quebrando os hábitos de estrutura que limitam a nota. Introdução: parar de começar com "Desde os primórdios da humanidade..." / "Ao longo da história..." / "Vivemos em um mundo globalizado..." Desenvolvimento: parar de começar todo parágrafo com "Outro aspecto importante..." Conclusão: parar de começar com "Diante do exposto, conclui-se que..." Alternativas criativas e sofisticadas para cada parte. Exercício: reescrever introduções e conclusões clichês. A frescura da escrita começa na variedade de início de parágrafo.', ['Reescreva estas 5 introduções clichês de forma criativa e original.', 'Escreva 5 formas diferentes de começar o último parágrafo (a conclusão) sem usar fórmulas.']),
  createLesson('g2-red-b3-l9', 'L9: Análise Crítica de Redações da Turma', 'redacao', 'Sessão de análise coletiva e respeitosa das redações da turma. Metodologia: 3-4 redações anonimizadas são projetadas. A turma avalia coletivamente, guiada pelo professor. Análise de C3 (a mais complexa): o argumento é desenvolvido? Tem evidência? Conecta com a tese? Análise de C5: a proposta tem os 5 elementos? É específica e viável? Foco no aprendizado coletivo: o que funciona em uma redação ensina o que todos devem fazer. Feedback construtivo como cultura de sala de aula.', ['Participe da análise coletiva: contribua com pelo menos 1 observação sobre C3 e 1 sobre C5.', 'O que você aprendeu vendo as redações dos colegas que você não via nas suas próprias?']),
  createLesson('g2-red-b3-l10', 'L10: Temas de Segurança Pública', 'redacao', 'Segurança pública como tema de redação. Subtemas: violência urbana, sistema penal, racismo policial, encarceramento em massa, reincidência, reinserção social, armas de fogo. Repertório: dados do Fórum Brasileiro de Segurança Pública, Atlas da Violência (IPEA), Constituição Art. 144, ECA. Conceitos: encarceramento em massa, genocídio negro, vitimização, "punitivismo". Como abordar a segurança pública sem cair em soluções simplistas (mais policiamento vs. mais presídios). Proposta: foco na prevenção, na reinserção e no combate à desigualdade.', ['Escreva uma redação sobre: "Estratégias para reduzir a reincidência criminal no Brasil".', 'Como você abordaria o racismo estrutural na segurança pública sem fugir ao tema?']),
  createLesson('g2-red-b3-l11', 'L11: Feedback Autogerenciado', 'redacao', 'Tornando-se seu próprio crítico. Desenvolvendo a metacognição na escrita: a capacidade de avaliar seu próprio texto com distância. Técnica: escrever a redação, esperar 30 minutos, reler como se fosse de outro aluno. Checklist pessoal de 15 itens: cada aluno cria o seu com base nos erros que mais comete. Revisão em voz alta: ler o texto em voz alta revela problemas de fluência e coesão que a leitura silenciosa não percebe. Autoedição: marcar com cores diferentes problemas de C1, C3, C4, C5. Autonomia: a habilidade de se autocorrigir é mais valiosa do que depender de feedback externo.', ['Escreva uma redação e depois a autoavalie usando seu checklist pessoal.', 'Que diferenças você percebeu entre sua autoavaliação e a avaliação do professor?']),
  createLesson('g2-red-b3-l12', 'L12: Sétima Redação — Pré-ENEM', 'redacao', 'Sétima redação: simulado no nível mais próximo possível do ENEM real. Tema com textos motivadores complexos e variados. Condições: cronômetro, folha de linhas (como o ENEM), sem consulta. Avaliação: aplicando os critérios exatos da banca. Projeção: em que patamar você estaria no ENEM se fosse hoje? O que falta para atingir 800+? Plano de ação para o 4º Bimestre: as últimas semanas de 2ª série antes da 3ª série.', ['Escreva a 7ª redação nas condições mais próximas do ENEM possível.', 'Calcule sua nota projetada. Para atingir 800, o que especificamente você precisa melhorar?']),
  createLesson('g2-red-b3-l13', 'L13: Construindo o Banco de Dados da Redação', 'redacao', 'Organizando todo o repertório acumulado no ano. Criando um "banco de dados" pessoal e organizado de: dados estatísticos por tema (10 temas × 3 dados cada = 30 dados), leis e documentos por tema (20 leis/documentos), filósofos e conceitos (15 filósofos × tema de aplicação), sociólogos e conceitos (10 sociólogos), eventos históricos por tema (20 eventos), obras literárias por tema (10 obras). Formato: fichas, documento digital, caderno. Este banco de dados é seu maior ativo para o ENEM.', ['Organize seu banco de dados pessoal de repertório de redação.', 'Para o tema "desigualdade social", quais itens do seu banco você usaria? Liste pelo menos 5.']),
  createLesson('g2-red-b3-l14', 'L14: Redação Nota 900+ — O que Falta?', 'redacao', 'Para quem já chega a 700-800: o que é preciso para chegar a 900+? A diferença entre 800 e 900 é geralmente em C3 (argumentação mais profunda e original) e C5 (proposta mais criativa e detalhada). O que é "argumentação original" no ENEM: mostrar uma perspectiva não óbvia, conectar áreas diferentes do conhecimento, revelar uma relação causal que vai além do senso comum. O que é "proposta criativa": um mecanismo específico, um agente incomum, uma ação nova. Analisando redações 880, 900, 960.', ['Analise esta redação nota 920: o que a coloca neste patamar?', 'Reescreva o argumento mais fraco desta redação tornando-o mais original e profundo.']),
  createLesson('g2-red-b3-l15', 'L15: Temas de Trabalho e Precarização', 'redacao', 'Trabalho e precarização no Brasil. Subtemas: uberização (trabalho por aplicativo), pejotização (falso MEI), trabalho infantil, trabalho escravo contemporâneo, desemprego jovem, reforma trabalhista (2017), sindicalismo, automação e desemprego. Repertório: CLT (1943), dados IBGE (taxa de desemprego, informalidade), Agenda 2030 ODS 8 (trabalho decente), reportagens sobre trabalhadores de plataforma. Proposta: regulamentação vs. flexibilização. Prática: redação sobre precarização do trabalho no Brasil digital.', ['Escreva uma redação sobre: "Os desafios da regulamentação do trabalho em plataformas digitais no Brasil".', 'Como a uberização afeta tanto o trabalhador individual quanto a sociedade em geral?']),
  createLesson('g2-red-b3-l16', 'L16: Revisão Pré-Bimestral', 'redacao', 'Revisão intensiva antes da avaliação bimestral. Revisão de C3: escrever um parágrafo de desenvolvimento com 3 camadas em 15 minutos. Revisão de C5: escrever uma proposta com 5 elementos em 5 minutos. Revisão de conectivos: preencher lacunas sem ver o gabarito. Revisão de introdução: escrever 2 introduções para o mesmo tema em 20 minutos. Teste de norma culta: 15 questões. Preparação emocional: você sabe fazer isso — confie no treinamento.', ['Execute a revisão pré-bimestral intensiva (1 hora de exercícios concentrados).', 'Qual é o seu plano para os 60 minutos da prova bimestral de redação?']),
  createLesson('g2-red-b3-l17', 'L17: Avaliação Bimestral — Redação', 'redacao', 'Avaliação bimestral: redação completa com tema proposto pelo professor. 60 minutos. Esta é uma das últimas avaliações formais da 2ª série. Demonstrar: tudo que foi aprendido no 3º Bimestre e ao longo do ano. Aplicar: tese avançada, argumentação em camadas, repertório pertinente, coesão sofisticada, proposta com 5 elementos detalhados. Foco total: sem distração, sem pressa, sem pânico. Você treinou para este momento.', ['Escreva a avaliação bimestral de Redação (60 minutos).', 'Após a devolutiva: identifique os erros que persistem e trace um plano final.']),
  createLesson('g2-red-b3-l18', 'L18: Revisão do Bimestre 3', 'redacao', 'Revisão do 3º Bimestre: intensidade do 2º semestre, técnicas argumentativas de alto impacto, tema livre, revisão de tipos de argumento, norma culta exaustiva, simulado 6, temas emergentes, estrutura criativa, análise coletiva, segurança pública, autoavaliação, simulado 7 pré-ENEM, banco de dados de repertório, nota 900+, trabalho/precarização, revisão pré-bimestral, prova bimestral. Balanço: onde você está agora? O que falta para a 3ª série?', ['Analise sua trajetória no 3º Bimestre: quais foram os maiores avanços?', 'O que você ainda precisa consolidar antes de entrar na 3ª série?']),
];

export const redLessonsB4: Lesson[] = [
  createLesson('g2-red-b4-l1', 'L1: 4º Bimestre — Reta Final da 2ª Série', 'redacao', 'O 4º Bimestre da 2ª série é a preparação final para a 3ª série, o ano do ENEM. Objetivos finais: consolidar consistência (escrever sempre acima de 700), eliminar erros residuais de norma, tornar o planejamento automatizado, fortalecer o banco de repertório. A diferença entre 2ª e 3ª série: na 3ª, o ritmo é mais intenso e o simulado final é o ENEM real. Preparar-se agora para esse ritmo. Autoavaliação honesta: em que patamar consistente você está? O que ainda é fraco?', ['Escreva uma redação de diagnóstico do 4º Bimestre.', 'O que você precisa conquistar neste último bimestre da 2ª série?']),
  createLesson('g2-red-b4-l2', 'L2: Argumento do Contra — Dominando a Concessão', 'redacao', 'A concessão argumentativa como técnica sofisticada. Nível 1: admitir que existe um contra-argumento. Nível 2: apresentar o contra-argumento de forma justa (sem distorcer). Nível 3: refutar com argumento mais forte. Nível 4: usar a concessão para fortalecer a tese (a tese prevalece APESAR da concessão). Estrutura: "É verdade que [contra-argumento]. No entanto, [refutação + argumento mais forte]." Diferença de conceder e recuar: ao conceder, você NÃO abandona sua tese — você a fortalece. Prática intensiva de concessão-refutação.', ['Escreva um parágrafo de concessão-refutação para o tema proposto.', 'Transforme estes argumentos unilaterais em argumentos com concessão e refutação.']),
  createLesson('g2-red-b4-l3', 'L3: Oitava Redação — Simulado Final', 'redacao', 'Oitava e última redação de simulado da 2ª série. Condições rigorosas. Meta: acima de 750. Avaliação: critérios máximos. Esta redação representa o nível que você chegou após 2 anos de prática. Feedback final e detalhado. O que levar para a 3ª série: os pontos fortes que você consolidou e as lacunas que ainda precisam de trabalho intensivo. A 3ª série começa do patamar em que você termina a 2ª.', ['Escreva a 8ª redação (simulado final da 2ª série).', 'Faça uma autoavaliação final: o que você consolida leva para a 3ª série? O que ainda precisa de trabalho?']),
  createLesson('g2-red-b4-l4', 'L4: Revisão Geral — Todos os Temas do Ano', 'redacao', 'Revisão temática rápida: todos os temas de redação cobertos no ano. Para cada tema: problema social central, argumentos mais sólidos, repertório específico, proposta mais específica. Criando um "mapa de temas" com links entre eles (desigualdade conecta com educação, saúde, trabalho, segurança). A redação do ENEM quase nunca é sobre um único tema — é sobre um problema que tem múltiplas dimensões. Praticar: dado um tema, identificar em 2 minutos os ângulos e as conexões.', ['Para cada tema estudado no ano, escreva em 1 linha: o problema social central e a proposta mais forte.', 'Qual tema você sente que está mais preparado para escrever? E o menos preparado?']),
  createLesson('g2-red-b4-l5', 'L5: Portfólio de Redações — Avaliação do Ano', 'redacao', 'Organização do portfólio de redações da 2ª série. Seleção: a primeira redação do ano, a melhor redação, a que mais evoluiu. Comparação visual e qualitativa: o que mudou em cada competência? Autoavaliação escrita: um texto reflexivo sobre sua trajetória como escritor na 2ª série. O portfólio como documento de aprendizado: não apenas notas, mas evidência de crescimento. Apresentar para os colegas: o que cada um mais se orgulha de ter aprendido.', ['Monte o portfólio de redações da 2ª série com autoavaliação de cada texto selecionado.', 'Escreva uma reflexão sobre sua jornada de aprendizado em Redação na 2ª série.']),
  createLesson('g2-red-b4-l6', 'L6: Prática de Planejamento — Velocidade e Qualidade', 'redacao', 'Planejamento em 8 minutos com qualidade máxima. Meta: após treinamento, o planejamento deve ser automático e rápido — deixando mais tempo para a escrita e a revisão. Prática: dado o tema, planejar em 8 minutos sem parar. Registro: escrever o planejamento no rascunho de forma concisa (não frases completas — palavras-chave). Comparação: planejar bem em 8 minutos é melhor do que planejar mal em 15. Automatização: depois de praticar muito, o planejamento fica no sangue — você já sabe como fazer.', ['Pratique 4 planejamentos de redação em 32 minutos (8 min cada).', 'Qual é mais difícil de planejar rápido: a tese, os argumentos ou a proposta?']),
  createLesson('g2-red-b4-l7', 'L7: Cartas, Manifestos e Outros Gêneros Dissertativos', 'redacao', 'Outros gêneros argumentativos além da dissertação. Carta argumentativa: usada em alguns vestibulares (UNICAMP). Manifesto: declaração coletiva de posição. Artigo de opinião: assinado, publicado em jornal. Carta aberta: ao público ou a uma instituição. Como a estrutura argumentativa é a mesma (tese, argumentos, conclusão) mas o formato, o registro e os destinatários mudam. Exercício: produzir uma carta argumentativa e um artigo de opinião sobre o mesmo tema. Preparação para vestibulares que exigem gêneros alternativos.', ['Escreva uma carta argumentativa sobre o mesmo tema de uma redação dissertativa que você já escreveu.', 'O que muda entre a dissertação do ENEM e a carta argumentativa do UNICAMP?']),
  createLesson('g2-red-b4-l8', 'L8: Simulado Final da 2ª Série', 'redacao', 'Avaliação final da 2ª série: redação completa e questionário de reflexão. Redação: 60 minutos, tema proposto pelo professor, avaliação plena. Questionário: 10 perguntas de reflexão sobre o aprendizado do ano. A nota desta redação representa o ponto de partida da 3ª série. Feedback final: o que consolidar e o que trabalhar nos próximos meses. Mensagem de encerramento: você chegou muito longe. A 3ª série é o momento de colher o que você plantou na 2ª. Continue praticando nas férias.', ['Escreva a avaliação final de Redação da 2ª série (60 minutos).', 'Responda: onde você estava no início e onde está agora? Qual foi seu maior crescimento?']),
  createLesson('g2-red-b4-l9', 'L9: Orientação para a 3ª Série', 'redacao', 'O que esperar da Redação na 3ª série. Ritmo: mais intenso, mais simulados, mais feedback, mais exigência. Temas: os mesmos temas, mas com mais profundidade exigida. Competências: a C3 e C5 serão trabalhadas em nível máximo. O ENEM real está no horizonte: cada redação da 3ª série conta. O que fazer nas férias: ler editoriais de qualidade (mínimo 3 por semana), praticar planejamentos (sem escrever), revisar o banco de repertório, adicionar 5 novas fichas por semana. A preparação começa no dia após as últimas provas da 2ª série.', ['O que você vai fazer durante as férias para manter e desenvolver a habilidade de redação?', 'Quais são seus 3 objetivos específicos de redação para a 3ª série?']),
  createLesson('g2-red-b4-l10', 'L10: Encerramento e Celebração', 'redacao', 'Última aula de Redação da 2ª série. Celebração: cada aluno lê sua melhor frase de todo o ano. Galeria de argumentos: frases mais poderosas escritas pela turma ao longo do ano. Mensagem do professor: o que ele/ela viu de crescimento em cada aluno. Gratidão: pela prática, pela constância, pela coragem de escrever e receber feedback. A habilidade de argumentar por escrito é uma das mais poderosas que um ser humano pode ter. Use-a bem. Boa 3ª série!', ['Leia sua melhor frase do ano para a turma.', 'Escreva uma mensagem de encorajamento para um colega sobre a jornada de Redação na 3ª série.']),
  createLesson('g2-red-b4-l11', 'L11: Prática Extra — Redação Criativa', 'redacao', 'Exercício de escrita criativa dentro da dissertação argumentativa. Usar imagens, metáforas, histórias brevíssimas (1-2 frases) como apoio ao argumento. Exemplo: "Como descrevia Carolina Maria de Jesus ao registrar a fome em seu diário, a pobreza não tem rosto abstrato — ela tem nome e endereço." Equilíbrio: a dissertação é argumentativa, não literária — a criatividade deve servir ao argumento. Praticar a criatividade controlada: expressiva, mas focada.', ['Escreva uma introdução que use uma imagem poética ou narrativa brevíssima para contextualizar o tema.', 'Como você equilibra criatividade e objetividade em uma dissertação argumentativa?']),
  createLesson('g2-red-b4-l12', 'L12: Exercícios de C5 — Banco de Propostas', 'redacao', 'Construindo um banco de propostas de intervenção. Para 15 temas diferentes, escrever a proposta com todos os 5 elementos. Tempo: 3-4 minutos por proposta. Objetivo: quando você chegar no ENEM e souber qual é o tema, já ter uma proposta mental pronta. As propostas por categoria: educação (agente: MEC, secretarias), saúde (agente: Ministério da Saúde, municípios), segurança (agente: poder judiciário, secretarias de segurança), ambiente (agente: IBAMA, municípios). Revisão: cada proposta do banco tem todos os 5 elementos?', ['Escreva propostas de intervenção para 10 temas em 40 minutos (4 min cada).', 'Revise cada proposta: todos os 5 elementos estão presentes? A proposta é viável?']),
  createLesson('g2-red-b4-l13', 'L13: Análise de Temas Reais do ENEM', 'redacao', 'Análise aprofundada dos últimos 5 temas reais do ENEM. Para cada um: identificar o problema social central, os textos motivadores usados, o recorte mais comum escolhido pelos candidatos, as propostas mais frequentes, os repertórios mais usados. O que torna um tema difícil: quando o problema não é óbvio. O que torna fácil: quando os argumentos são abundantes. Construindo flexibilidade para encarar qualquer tema. Prática: dado um tema real, produzir planejamento em 5 minutos.', ['Para o tema real do ENEM 2022, produza um planejamento completo em 8 minutos.', 'Qual foi o tema mais difícil dos últimos 5 ENEMs? Por que ele é desafiador?']),
  createLesson('g2-red-b4-l14', 'L14: Leitura e Repertório — Atividade Final', 'redacao', 'Atividade final de leitura e construção de repertório. Leitura de 3 textos longos (editorial, artigo acadêmico simplificado, texto literário) e extração de: 1 dado, 1 conceito, 1 argumento utilizável em redação. Discussão: como cada texto pode ser usado em contextos diferentes. Revisão final do banco de repertório pessoal: está organizado? Está completo? Faltam categorias? Compromisso: nas férias, adicionar pelo menos 10 novas fichas ao banco.', ['Leia os 3 textos e extraia: 1 dado, 1 conceito, 1 argumento de cada.', 'Seu banco de repertório está pronto para a 3ª série? O que falta?']),
  createLesson('g2-red-b4-l15', 'L15: Feedback Final Individual', 'redacao', 'Sessão de feedback final individual. O professor devolve todas as redações avaliadas do ano com uma síntese por competência. Análise do arco completo: como cada competência evoluiu de janeiro a dezembro. Pontos fortes consolidados: o que o aluno pode confiar que já sabe fazer. Pontos de melhoria para a 3ª série: o que precisa de atenção intensiva. Recomendações de prática nas férias: específicas por aluno. Esta sessão é o mapa para a preparação do ano do ENEM.', ['Receba e processe o feedback final: quais são seus pontos fortes e os pontos de melhoria?', 'Escreva um plano de ação para as férias e para o início da 3ª série baseado no feedback.']),
  createLesson('g2-red-b4-l16', 'L16: Revisão Geral e Última Prática', 'redacao', 'Última aula de revisão: teste rápido cobrindo todos os conteúdos do ano de redação na 2ª série. Questões sobre: competências do ENEM, tipos de argumento, conectivos, estrutura da dissertação, repertório cultural, estratégias de introdução e conclusão, proposta de intervenção. Em seguida: última prática de planejamento (sem escrever o texto completo) — 2 temas em 16 minutos. Verificando a internalização do conhecimento.', ['Faça o teste de revisão geral (20 questões sobre redação).', 'Faça 2 planejamentos de redação em 16 minutos. A estrutura está automatizada?']),
  createLesson('g2-red-b4-l17', 'L17: Motivação Final — Por que a Redação Importa', 'redacao', 'Mensagem final motivacional sobre o aprendizado de Redação. Por que a dissertação argumentativa importa além do ENEM: na universidade (trabalhos, monografias), no trabalho (relatórios, e-mails persuasivos, propostas), na vida cidadã (petições, cartas, debate público). A habilidade de argumentar com clareza é um dos superpoderes do século XXI. Você não aprendeu a escrever uma dissertação — você aprendeu a pensar de forma organizada, analisar problemas e propor soluções. Isso vai com você para sempre.', ['O que a Redação te ensinou além de como escrever um texto?', 'Escreva uma mensagem de motivação para quem está começando a aprender a dissertar.']),
  createLesson('g2-red-b4-l18', 'L18: Encerramento Formal da 2ª Série', 'redacao', 'Encerramento formal do ano letivo de Redação na 2ª série. Galeria final: os melhores argumentos, as introduções mais criativas, as propostas mais específicas escritas pela turma. Cada aluno apresenta seu melhor texto do ano. Celebração coletiva: um ano de aprendizado, crescimento, erros e acertos que valeram a pena. Para a 3ª série: você tem base. Agora é hora de construir o teto. O ENEM real está próximo — e você está mais pronto do que no início deste ano.', ['Apresente seu melhor texto do ano de Redação.', 'O que você leva da 2ª série de Redação para a 3ª série?']),
];
